      default:
        return <Home onStart={() => setCurrentView(AppView.WORKSPACE)} />;
    }
  };

  return (
    <Layout 
      currentView={currentView} 
      setView={setCurrentView}
      isDark={isDark}
      toggleTheme={() => setIsDark(!isDark)}
    >
      {renderView()}
    </Layout>
  );
};

