import { GoogleGenAI, Type, Modality } from "@google/genai";

/**
 * Utility for exponential backoff retries to handle transient RPC/XHR errors.
 */
async function retry<T>(fn: () => Promise<T>, retries = 3, delay = 1000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const isTransient = error?.message?.includes('xhr error') || 
                        error?.message?.includes('500') || 
                        error?.message?.includes('UNAVAILABLE') ||
                        error?.message?.includes('limit');
    if (retries > 0 && isTransient) {
      console.warn(`Transient error detected. Retrying in ${delay}ms... (${retries} attempts left)`);
      await new Promise(resolve => setTimeout(resolve, delay));
      return retry(fn, retries - 1, delay * 2);
    }
    throw error;
  }
}

/**
 * Stage 1 & 2: Multimodal Analysis and Audio Synthesis.
 * Extracts vocal identity and emotional context to ensure "acting" in the dub.
 */
export const processDubbingPipeline = async (
  fileData: string, 
  mimeType: string,
  targetLang: string
) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  // Ensure the base64 data is clean
  const cleanData = fileData.replace(/\s/g, ''); 

  return await retry(async () => {
    // 1. Multimodal Analysis using the high-reasoning Pro model
    const analysisResponse = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: [{
        parts: [
          { inlineData: { data: cleanData, mimeType } },
          { text: `Analyze the provided media and output a JSON response for a dubbing pipeline. 
                   1. sourceText: The verbatim transcription of the original speech.
                   2. translatedText: A natural, high-quality translation into ${targetLang}.
                   3. gender: Identify the speaker's gender as 'male' or 'female'.
                   4. emotion: Detect the primary emotional tone (e.g., 'excited', 'sad', 'angry', 'calm').
                   5. vocalIdentity: A brief technical description of the voice texture (e.g., 'raspy bass', 'bright soprano').
                   6. prosodyInstruction: Guidance for a voice actor to match the source's speed and pitch.
                   7. confidence: A float between 0 and 1 representing analysis certainty.

                   If no speech is found, provide a placeholder JSON with empty strings.` }
        ]
      }],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            sourceText: { type: Type.STRING },
            translatedText: { type: Type.STRING },
            gender: { type: Type.STRING },
            emotion: { type: Type.STRING },
            vocalIdentity: { type: Type.STRING },
            prosodyInstruction: { type: Type.STRING },
            confidence: { type: Type.NUMBER }
          },
          required: ["sourceText", "translatedText", "gender", "emotion", "vocalIdentity", "prosodyInstruction", "confidence"]
        }
      }
    });

    const responseText = analysisResponse.text;
    if (!responseText) {
      throw new Error("Neural model returned an empty response. Please check if the file has clear audio.");
    }

    const metadata = JSON.parse(responseText);

    // Safety check for metadata content
    if (!metadata.sourceText || metadata.sourceText.trim() === "") {
      throw new Error("No speech detected in the provided file. Please try a different recording.");
    }

    // Determine voice based on detected gender
    const voiceName = (metadata.gender?.toLowerCase().includes('female')) ? 'Kore' : 'Fenrir';

    // 2. Speech Synthesis using the high-fidelity TTS model
